<?php get_header(); ?><main class="content"><?php if (is_home()) : ?><div class="eyebrow">Blog</div><h1>Artikelen en updates</h1><?php endif; ?><?php if (have_posts()) : ?><div class="post-grid"><?php while (have_posts()) : the_post(); ?><a class="post-card" href="<?php the_permalink(); ?>"><div class="post-meta"><?php echo esc_html(get_the_date()); ?></div><h2 style="font-size:1.55rem"><?php the_title(); ?></h2><?php the_excerpt(); ?></a><?php endwhile; ?></div><?php the_posts_pagination(); ?><?php else : ?><p>Er zijn nog geen berichten gepubliceerd.</p><?php endif; ?></main><?php get_footer(); ?>